import React from 'react';

const Controls = ({ onStart, onPause, onStop, onReset }) => {
  return (
    <div className="flex space-x-4 mt-4">
      <button onClick={onStart} className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600">Start</button>
      <button onClick={onPause} className="px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">Pause</button>
      <button onClick={onStop} className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600">Stop</button>
      <button onClick={onReset} className="px-4 py-2 bg-gray-500 text-white rounded-lg hover:bg-gray-600">Reset</button>
    </div>
  );
};

export default Controls;
